import React, { useState, useEffect } from 'react';

const EditOutflow = ({ outflow, handleUpdate, locations, materials, employees, projects}) => {
  
  
  const [editedOutflow, setEditedOutflow] = useState({ ...outflow });
  const [showExtras, setShowExtras] = useState(false);
  const [availableMaterials, setAvailableMaterials] = useState([]);
  const [availableWidths, setAvailableWidths] = useState([]);
  const [availableLots, setAvailableLots] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      if (editedOutflow.location) {
        try {
          const [responseMaterial] = await Promise.all([
            fetch(`http://localhost:8081/PurchasesAPI/materialid/${editedOutflow.location}`),
          ]);
  
          const materialList = await responseMaterial.json();
  
          setAvailableMaterials(materialList);
        } catch (error) {
          console.error('Error fetching material data:', error);
        }
      }
      if (editedOutflow.materialid) {
        try {
          const [responseWidth] = await Promise.all([
            fetch(`http://localhost:8081/PurchasesAPI/widths/${editedOutflow.location}/${editedOutflow.materialid}`),
          ]);
  
          const materialWidth = await responseWidth.json();
  
          setAvailableWidths(materialWidth);
        } catch (error) {
          console.error('Error fetching material data:', error);
        }
      } else {
        setEditedOutflow((prevPurchase) => ({
          ...prevPurchase,
          width: '',
        }));
      }
      if (editedOutflow.width) {
        try {
          const [responseLot] = await Promise.all([
            fetch(`http://localhost:8081/PurchasesAPI/lots/${editedOutflow.location}/${editedOutflow.materialid}/${editedOutflow.width}`),
          ]);
  
          const materialLot = await responseLot.json();
  
          setAvailableLots(materialLot);
        } catch (error) {
          console.error('Error fetching material data:', error);
        }
      } else {
        setEditedOutflow((prevPurchase) => ({
          ...prevPurchase,
          lotnumber: '',
        }));
      }
    };
  
    fetchData();
    
  }, [editedOutflow.location, editedOutflow.materialid, editedOutflow.width]);
  const handleChange = (e) => {
    const { name, value } = e.target;
    
    if (name === 'location') {
      setEditedOutflow((prevOutflow) => ({
        ...prevOutflow,
        [name]: value,
      }));
    } else if (name === 'materialid') {
      const selectedMaterial = materials.find(material => material.matid === value);
      
      if (selectedMaterial) {
        setEditedOutflow((prevOutflow) => ({
          ...prevOutflow,
          [name]: value,
          materialname: selectedMaterial.name,
        }));
        
        if (selectedMaterial.extras === 1) {
          setShowExtras(true);
        } else {
          setShowExtras(false);
          setEditedOutflow((prevPurchase) => ({
            ...prevPurchase,
            lotnumber: '',
            width: null ,
          }));
          
        }
      }
    } else {
      setEditedOutflow((prevOutflow) => ({
        ...prevOutflow,
        [name]: value,
      }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {

      handleAdd(newOutflow);
      setEditedOutflow(initialOutflowState);
      setShowExtras(false);
    } catch (error) {
      console.error('Error handling the form submission:', error);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="add-purchase-form">
    <div>
      <label>Location:</label>
      <select name="location" value={editedOutflow.location || ''} onChange={handleChange} required>
        <option value="">Select a location</option>
        {locations.map((location) => (
          <option key={location.id} value={location.id}>
            {location.locationname}
          </option>
        ))}
      </select>
    </div>
    {editedOutflow.location && (
      <div>
    <div>
      <label>Material ID:</label>
      <select
        name="materialid"
        value={editedOutflow.materialid || ''}
        onChange={handleChange}
        required
      >
        <option value="">Select a material</option>
        {availableMaterials.map((material) => (
          <option key={material} value={material}>
            {material}
          </option>
        ))}
      </select>
    </div>
    <div>
      <label>Material Name:</label>
      <input type="text" name="materialname" value={editedOutflow.materialname || ''} readOnly required />
    </div>
    </div>
    )}
    {showExtras && editedOutflow.materialname &&(
      <div>
        <label>Width:</label>
      <select
        name="width"
        value={editedOutflow.width || ''}
        onChange={handleChange}
        required
      >
        <option value="">Select a width</option>
        {availableWidths.map((width) => (
          <option key={width} value={width}>
            {width}
          </option>
        ))}
      </select>
      </div>
    )}
    {showExtras && editedOutflow.width && (
      <div>
        <label>Lot No:</label>
      <select
        name="lotnumber"
        value={editedOutflow.lotnumber || ''}
        onChange={handleChange}
        required
      >
        <option value="">Select a lot #</option>
        {availableLots.map((lot) => (
          <option key={lot} value={lot}>
            {lot}
          </option>
        ))}
      </select>
      </div>
    )}
    {showExtras && editedOutflow.lotnumber && (
      <div>
        <label>Quantity:</label>
        <input type="text" name="quantity" value={editedOutflow.quantity || ''} onChange={handleChange} required />
      </div>
    )}
    {!showExtras && editedOutflow.materialid && (
      <div>
        <label>Quantity:</label>
        <input type="text" name="quantity" value={editedOutflow.quantity || ''} onChange={handleChange} required />
      </div>
    )}
    {editedOutflow.quantity && (
    <div>
      <label>Employee:</label>
      <select
        name="employee"
        value={editedOutflow.employee || ''}
        onChange={handleChange}
        required
      >
        <option value="">Select an Employee</option>
        {employees.map((employee) => (
          <option key={employee.empid} value={employee.empid}>
            {employee.name}
          </option>
        ))}
      </select>
    </div>
    )}
    {editedOutflow.employee && (
    <div>
      <label>Project:</label>
      <select
        name="project"
        value={editedOutflow.project || ''}
        onChange={handleChange}
        required
      >
        <option value="">Select a Project</option>
        {projects.map((project) => (
          <option key={project.prid} value={project.prid}>
            {project.name}
          </option>
        ))}
      </select>
    </div>
    )}
    <button type="submit" className="add_purchase_btn">
      Add Outflow
    </button>
  </form>
);
};

export default EditOutflow;
